let[@axiom] rbtree_positive_num_black_is_not_rb_leaf = fun (l : (int rbtree)) -> fun (n : int) -> (((num_black l n) && (n > 0)) #==> (not (rb_leaf l)))
let[@axiom] rbtree_no_rb_leaf_exists_ch = fun (l : (int rbtree)) -> fun ((l1 [@ex]) : (int rbtree)) -> fun ((l2 [@ex]) : (int rbtree)) -> ((not (rb_leaf l)) #==> ((rb_lch l l1) && (rb_rch l l2)))
let[@axiom] rbtree_no_rb_leaf_exists_rb_root = fun (l : (int rbtree)) -> fun ((x [@ex]) : int) -> ((not (rb_leaf l)) #==> (rb_root l x))
let[@axiom] rbtree_no_rb_leaf_exists_rb_root_color = fun (l : (int rbtree)) -> fun ((x [@ex]) : bool) -> ((not (rb_leaf l)) #==> (rb_root_color l x))
let[@axiom] no_red_red_lt = fun (v : (int rbtree)) -> fun (lt : (int rbtree)) -> (((no_red_red v) && (rb_lch v lt)) #==> (no_red_red lt))
let[@axiom] no_red_red_rt = fun (v : (int rbtree)) -> fun (rt : (int rbtree)) -> (((no_red_red v) && (rb_rch v rt)) #==> (no_red_red rt))
let[@axiom] num_black_root_red_lt_same = fun (v : (int rbtree)) -> fun (lt : (int rbtree)) -> fun (h : int) -> (((rb_root_color v true) && ((num_black v h) && (rb_lch v lt))) #==> (num_black lt h))
let[@axiom] num_black_root_red_rt_same = fun (v : (int rbtree)) -> fun (rt : (int rbtree)) -> fun (h : int) -> (((rb_root_color v true) && ((num_black v h) && (rb_rch v rt))) #==> (num_black rt h))
let[@axiom] num_black_root_black_lt_minus_1 = fun (v : (int rbtree)) -> fun (lt : (int rbtree)) -> fun (h : int) -> (((rb_root_color v false) && ((num_black v h) && (rb_lch v lt))) #==> (num_black lt (h - 1)))
let[@axiom] num_black_root_black_rt_minus_1 = fun (v : (int rbtree)) -> fun (rt : (int rbtree)) -> fun (h : int) -> (((rb_root_color v false) && ((num_black v h) && (rb_rch v rt))) #==> (num_black rt (h - 1)))
let[@axiom] black_lt_black_num_black_gt_1 = fun (v : (int rbtree)) -> fun (lt : (int rbtree)) -> fun (h : int) -> (((num_black v h) && ((rb_lch v lt) && ((rb_root_color v false) && (rb_root_color lt false)))) #==> (h > 1))
let[@axiom] black_rt_black_num_black_gt_1 = fun (v : (int rbtree)) -> fun (rt : (int rbtree)) -> fun (h : int) -> (((num_black v h) && ((rb_rch v rt) && ((rb_root_color v false) && (rb_root_color rt false)))) #==> (h > 1))
let[@axiom] no_red_red_root_red_lt_not_red = fun (v : (int rbtree)) -> fun (lt : (int rbtree)) -> (((no_red_red v) && ((rb_lch v lt) && (rb_root_color v true))) #==> (not (rb_root_color lt true)))
let[@axiom] no_red_red_root_red_rt_not_red = fun (v : (int rbtree)) -> fun (rt : (int rbtree)) -> (((no_red_red v) && ((rb_rch v rt) && (rb_root_color v true))) #==> (not (rb_root_color rt true)))
let[@axiom] rbtree_num_black_0_rb_leaf = fun (l : (int rbtree)) -> (((num_black l 0) && (not (rb_root_color l true))) #==> (rb_leaf l))
let[@axiom] rbtree_leaf_or_not = fun (l : (int rbtree)) -> ((rb_leaf l) || (not (rb_leaf l)))